let passed = 0, failed = 0;
function runTest(name, fn) { try { fn(); passed++; console.log("PASS: " + name); } catch(e) { failed++; console.log("FAIL: " + name + " — " + e.message); } }
runTest("parse basic CSV", () => { const r = parseCSV("name,age
Alice,30
Bob,25
"); assert.strictEqual(r.length, 2); });
runTest("parse without trailing newline", () => { const r = parseCSV("name,age
Alice,30
Bob,25"); assert.strictEqual(r.length, 2, "Expected 2 but got " + r.length); });
